def on_click_lst_files():
    if lst_files.items:
        txt_filename.caption = lst_files.items[lst_files.list_index]

def on_double_click_lst_files():
    on_click_btn_ok()

def on_enter_lst_files():
    on_click_btn_ok()

def on_click_btn_ok():
    import sys
    if txt_filename.caption:
        filepath = os.path.join(os.getcwd(), txt_filename.caption)
        try:
            with open(filepath, 'w') as f:
                f.write(getattr(sys, '_shared_editor_text', ''))
            sys._shared_filename = filepath
            msgbox(f"File successfully saved:\n{filepath}")
            load_form('editor.json')
        except Exception as e:
            msgbox(f"Error saving:\n{e}")
    else:
        msgbox("Please enter a filename.")
